import{_ as t,o,c as a,ag as i}from"./chunks/framework.6ZJjlmu_.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Event Monitor","text":"","tagline":"Unity event tracing — record who subscribes, unsubscribes, and when events fire — with zero manual instrumentation.","actions":[{"theme":"brand","text":"Quick Start","link":"/guide/quick-start"},{"theme":"alt","text":"Core concepts","link":"/concepts/event-bus-and-records"}]},"features":[{"title":"IL Post-Processor","details":"Injects tracking into event add/remove accessors and common invocation call sites after compilation."},{"title":"Redux-style timeline","details":"Immutable SUB, UNSUB, and INVOKE records with filtering, stats, and export to Plain Text, CSV, JSON, or Markdown."},{"title":"Live subscribers","details":"Inspect the current graph of listeners per event, with optional time-travel replay of subscriber state."},{"title":"Optional payloads","details":"Capture invocation arguments when you need them; keep overhead low when you do not."},{"title":"Session save/load & compare","details":"Export `.emsession.json`, reload read-only sessions, and compare two captures with per-event deltas."},{"title":"Diagnostics toolkit","details":"Leak detection, invoke timing, exception breadcrumbs, growth alerts, diff view, and manual re-fire."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function s(r,e,l,d,h,c){return o(),a("div",null,[...e[0]||(e[0]=[i('<h2 id="what-is-event-monitor" tabindex="-1">What is Event Monitor? <a class="header-anchor" href="#what-is-event-monitor" aria-label="Permalink to &quot;What is Event Monitor?&quot;">​</a></h2><p>Event Monitor is a <strong>Unity Editor</strong> tool for teams that rely on <strong>C# events</strong> for gameplay, UI, or architecture. It answers questions such as:</p><div class="info custom-block"><p class="custom-block-title">Version note</p><p>Event Monitor is tested on both Unity 6 LTS (<code>6000.3.7f1</code>, <code>6000.4.2f1</code>) and Unity <code>2022.3.62f3</code>. See the compatibility table in <a href="./guide/installation.html">Installation</a>.</p></div><ul><li>Who subscribed to this event, and from which type and method?</li><li>When did it fire, and how many handlers were attached at that moment?</li><li>How did the listener graph evolve over a Play session?</li></ul><p>The workflow is inspired by <strong>Redux DevTools</strong>: an append-only log, derived subscriber state, and <strong>time travel</strong> to inspect that state at a chosen point in the timeline.</p><h2 id="who-is-it-for" tabindex="-1">Who is it for? <a class="header-anchor" href="#who-is-it-for" aria-label="Permalink to &quot;Who is it for?&quot;">​</a></h2><p>Projects with <strong>event-driven</strong> code paths where debugging “who listened, and why did this run?” otherwise means breakpoints, logging sprawl, or guesswork.</p><h2 id="what-it-is-not" tabindex="-1">What it is not <a class="header-anchor" href="#what-it-is-not" aria-label="Permalink to &quot;What it is not&quot;">​</a></h2><p>Event Monitor is a <strong>development-time</strong> observability tool inside the Editor. It is not a runtime analytics pipeline, a replacement for Unity Profiler, or a general-purpose logger.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li>Follow the <a href="./guide/quick-start.html">Quick Start</a> to open the window and read your first records.</li><li>See <a href="./guide/installation.html">Installation</a> for Unity version and package requirements.</li><li>Browse <a href="./how-to/payload-capture.html">How-to guides</a> for payloads, ILPP diagnostics, exports, <a href="./how-to/session-save-load.html">session save/load</a>, <a href="./how-to/leak-detection.html">leak detection</a>, <a href="./how-to/invoke-timing.html">invoke timing</a>, <a href="./how-to/exception-breadcrumbs.html">exception breadcrumbs</a>, and <a href="./how-to/subscriber-growth-alerts.html">subscriber growth alerts</a>.</li></ul>',11)])])}const u=t(n,[["render",s]]);export{m as __pageData,u as default};
